// floviq · Calc TradingDate (free edition)
// Find the most recent trading day that has TWSE data.
// Rule: walk back from today-1, skip weekends, and for each weekday candidate call the TWSE T86 endpoint and check its stat field.

const tpe = $now.setZone('Asia/Taipei');
const todayStr = tpe.toFormat('yyyy-MM-dd');
const weekdayMap = ['日', '一', '二', '三', '四', '五', '六'];
const todayWeekday = weekdayMap[tpe.weekday % 7];

let tradingDate = null;
let tradingDateFmt = null;

for (let i = 1; i <= 14; i++) {
  const d = tpe.minus({ days: i });
  // n8n DateTime weekday: 1=Mon, 2=Tue, ..., 6=Sat, 7=Sun
  if (d.weekday === 6 || d.weekday === 7) continue;

  const dStr = d.toFormat('yyyyMMdd');
  try {
    const resp = await this.helpers.httpRequest({
      method: 'GET',
      url: 'https://www.twse.com.tw/rwd/zh/fund/T86',
      qs: { date: dStr, selectType: 'ALL', response: 'json' },
      headers: { 'User-Agent': 'Mozilla/5.0 (compatible; floviq)' },
      timeout: 10000,
      json: true,
    });
    if (resp && resp.stat === 'OK' && Array.isArray(resp.data) && resp.data.length > 0) {
      tradingDate = dStr;
      tradingDateFmt = d.toFormat('yyyy-MM-dd');
      break;
    }
  } catch (e) {
    // A single fetch failed (network / TWSE 5xx) -> move on to the next candidate
    continue;
  }
}

if (!tradingDate) {
  throw new Error('No recent trading day found (TWSE returned no data across the last 14 days). The TWSE service may be down; please retry later.');
}

return [{
  json: {
    todayDate: todayStr,
    todayWeekday,
    tradingDate,
    tradingDateFmt,
  },
}];

// floviq · pre-market-briefing · format & enrich data for AI prompt

const tpe = $now.setZone('Asia/Taipei');
const dateStr = tpe.toFormat('yyyy-MM-dd');
const weekdayMap = ['日', '一', '二', '三', '四', '五', '六'];
const weekday = weekdayMap[tpe.weekday % 7];

const trading = $('Calculate Trading Date').first().json;
const tradingDateFmt = trading.tradingDateFmt;

const cfg = $('Set Configuration Parameters').first().json;
const topN = Number(cfg.topN) || 5;
const promptStyle = cfg.promptStyle || 'Neutral';
const watchlistStr = String(cfg.watchlist || '').trim();
const watchlist = watchlistStr ? watchlistStr.split(/[,，\s]+/).map((s) => s.trim()).filter(Boolean) : [];

// Parse a possibly HTML-wrapped / comma-formatted value into a finite number (default 0)
const toNum = (s) => {
  const cleaned = String(s == null ? '' : s).replace(/<[^>]+>/g, '').replace(/[,\s]/g, '').trim();
  if (cleaned === '' || cleaned === '--') return 0;
  const n = Number(cleaned);
  return Number.isFinite(n) ? n : 0;
};

const lookup = (fields, candidates) => {
  for (const name of candidates) {
    const idx = fields.indexOf(name);
    if (idx !== -1) return idx;
  }
  return -1;
};

// ---------- 1. TWSE T86 (institutional net buy/sell) ----------
let foreignTopBuyText = '無資料';
let foreignTopSellText = '無資料';
let hasT86 = false;
try {
  const t86 = $('Fetch TWSE Fund Data').first().json;
  const fields = t86.fields || [];
  const data = t86.data || [];
  if (Array.isArray(fields) && Array.isArray(data) && data.length > 0) {
    const codeIdx = lookup(fields, ['證券代號']);
    const nameIdx = lookup(fields, ['證券名稱']);
    const netIdx = lookup(fields, [
      '外陸資買賣超股數(不含外資自營商)',
      '外資及陸資(不含外資自營商)買賣超股數',
      '外資買賣超股數',
    ]);
    if (codeIdx === -1 || nameIdx === -1 || netIdx === -1) {
      throw new Error(`TWSE T86 schema changed (unexpected fields). fields=${JSON.stringify(fields)}`);
    }
    const rows = data
      .map((r) => ({
        code: String(r[codeIdx] || '').trim(),
        name: String(r[nameIdx] || '').trim(),
        net: toNum(r[netIdx]),
      }))
      .filter((r) => r.code);
    const sortedDesc = [...rows].sort((a, b) => b.net - a.net);
    const topBuy = sortedDesc.slice(0, topN);
    const topSell = sortedDesc.slice(-topN).reverse();
    const fmtK = (shares) => {
      const k = Math.round(shares / 1000);
      const sign = k > 0 ? '+' : '';
      return `${sign}${k.toLocaleString('en-US')} 千股`;
    };
    foreignTopBuyText = topBuy.map((r, i) => `${i + 1}. ${r.code} ${r.name} ${fmtK(r.net)}`).join('\n');
    foreignTopSellText = topSell.map((r, i) => `${i + 1}. ${r.code} ${r.name} ${fmtK(r.net)}`).join('\n');
    hasT86 = true;
  }
} catch (e) {
  // On a schema change, re-throw so the user sees it instead of silently emitting bad data
  if (String(e.message || '').includes('schema changed')) throw e;
  // Other failures (no data / holiday) -> degrade gracefully
}

// ---------- 2. TWSE MI_INDEX (market index + limit up/down) ----------
let limitUpText = '無';
let limitDownText = '無';
let limitUpCount = 0;
let limitDownCount = 0;
let taiexText = '資料暫缺';
try {
  const mi = $('Fetch TWSE Market Index').first().json;
  const tables = mi.tables || [];
  if (Array.isArray(tables) && tables.length > 0) {
    // Find the table containing every stock (its fields include the close-price, up/down-sign and price-change columns)
    const stocksTable = tables.find((t) => {
      const f = t && t.fields;
      return Array.isArray(f) && f.includes('收盤價') && f.includes('漲跌(+/-)') && f.includes('漲跌價差');
    });
    if (stocksTable) {
      const f = stocksTable.fields;
      const codeIdx = lookup(f, ['證券代號']);
      const nameIdx = lookup(f, ['證券名稱']);
      const closeIdx = lookup(f, ['收盤價']);
      const dirIdx = lookup(f, ['漲跌(+/-)']);
      const diffIdx = lookup(f, ['漲跌價差']);
      if ([codeIdx, nameIdx, closeIdx, dirIdx, diffIdx].some((i) => i === -1)) {
        throw new Error(`MI_INDEX daily quotes table schema changed (unexpected fields). fields=${JSON.stringify(f)}`);
      }
      const ups = [];
      const downs = [];
      for (const r of stocksTable.data || []) {
        const close = toNum(r[closeIdx]);
        const diff = toNum(r[diffIdx]);
        const dirHtml = String(r[dirIdx] || '');
        const sign = dirHtml.includes('red') ? 1 : dirHtml.includes('green') ? -1 : 0;
        if (close <= 0 || sign === 0) continue;
        const prev = close - sign * diff;
        if (prev <= 0) continue;
        const pct = (sign * diff) / prev * 100;
        const item = {
          code: String(r[codeIdx] || '').trim(),
          name: String(r[nameIdx] || '').trim(),
          pct: Math.round(pct * 100) / 100,
        };
        if (pct >= 9.9) ups.push(item);
        else if (pct <= -9.9) downs.push(item);
      }
      limitUpCount = ups.length;
      limitDownCount = downs.length;
      limitUpText = ups.length === 0 ? '無' : ups.slice(0, topN).map((r) => `${r.code} ${r.name} (+${r.pct.toFixed(2)}%)`).join('、') + (ups.length > topN ? ` 等共 ${ups.length} 檔` : '');
      limitDownText = downs.length === 0 ? '無' : downs.slice(0, topN).map((r) => `${r.code} ${r.name} (${r.pct.toFixed(2)}%)`).join('、') + (downs.length > topN ? ` 等共 ${downs.length} 檔` : '');
    }

    // Market index — find the price-index table and pick the TAIEX capitalization-weighted index row
    const priceTable = tables.find((t) => {
      const f = t && t.fields;
      return Array.isArray(f) && f.includes('指數') && f.includes('收盤指數') && f.includes('漲跌(+/-)');
    });
    if (priceTable) {
      const f = priceTable.fields;
      const idxIdx = lookup(f, ['指數']);
      const closeIdx = lookup(f, ['收盤指數']);
      const dirIdx = lookup(f, ['漲跌(+/-)']);
      const ptsIdx = lookup(f, ['漲跌點數']);
      const pctIdx = lookup(f, ['漲跌百分比(%)']);
      const taiex = (priceTable.data || []).find((r) => String(r[idxIdx] || '').includes('發行量加權股價指數'));
      if (taiex) {
        const dirHtml = String(taiex[dirIdx] || '');
        const sign = dirHtml.includes('red') ? '+' : dirHtml.includes('green') ? '-' : '';
        taiexText = `加權指數 ${taiex[closeIdx]}（${sign}${taiex[ptsIdx]} 點 / ${sign}${taiex[pctIdx]}%）`;
      }
    }
  }
} catch (e) {
  if (String(e.message || '').includes('schema changed')) throw e;
}

// ---------- 3. CNYES news ----------
let newsText = '資料暫缺';
try {
  const cn = $('Fetch CNYES Headlines').first().json;
  const list = (cn && cn.items && cn.items.data) || [];
  if (Array.isArray(list) && list.length > 0) {
    const decode = (s) => String(s || '')
      .replace(/&lt;/g, '<')
      .replace(/&gt;/g, '>')
      .replace(/&amp;/g, '&')
      .replace(/&quot;/g, '"')
      .replace(/&#39;/g, "'")
      .replace(/&nbsp;/g, ' ');
    const top3 = list.slice(0, 3).map((n, i) => {
      const title = decode(n.title || '').trim();
      const summary = decode(n.summary || '').replace(/\s+/g, ' ').trim();
      const short = summary.length > 80 ? summary.slice(0, 80) + '…' : summary;
      return `${i + 1}. ${title}${short ? `\n   ${short}` : ''}`;
    });
    newsText = top3.join('\n');
  }
} catch (e) {
  // A news fetch failure must not block the workflow
}

// ---------- Assemble prompt variables ----------
const noDataMode = !hasT86;

return [
  {
    json: {
      date: dateStr,
      weekday,
      trading_date_fmt: tradingDateFmt,
      prompt_style: promptStyle,
      watchlist: watchlist.length === 0 ? '（未設定）' : watchlist.join(', '),
      top_n: topN,
      foreign_top_buy_text: foreignTopBuyText,
      foreign_top_sell_text: foreignTopSellText,
      limit_up_count: limitUpCount,
      limit_down_count: limitDownCount,
      limit_up_text: limitUpText,
      limit_down_text: limitDownText,
      taiex_text: taiexText,
      news_text: newsText,
      no_data_mode: noDataMode,
    },
  },
];

