// floviq · pre-market-briefing · compose Telegram message from AI JSON
// Input: the OpenAI node's message.content (a JSON string) or an already-parsed object
// Output: a plain-text message (avoids Markdown special-character escaping pitfalls)

const input = $input.first().json;
const tradingDateFmt = $('Calculate Trading Date').first().json.tradingDateFmt;

// Locate the AI JSON: the langchain openAi node usually puts the result in message.content or content
let aiRaw =
  input?.message?.content ??
  input?.choices?.[0]?.message?.content ??
  input?.content ??
  input;

let ai;
if (typeof aiRaw === 'string') {
  // Strip any surrounding markdown code fence
  const cleaned = aiRaw.trim().replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/```$/g, '').trim();
  try {
    ai = JSON.parse(cleaned);
  } catch (e) {
    throw new Error(`Failed to parse AI JSON: ${e.message}. Raw output: ${aiRaw.slice(0, 200)}`);
  }
} else if (typeof aiRaw === 'object' && aiRaw !== null) {
  ai = aiRaw;
} else {
  throw new Error(`Could not read content from the OpenAI node. input keys=${Object.keys(input || {}).join(',')}`);
}

// Schema-safety defaults
const headline = String(ai.headline || '盤前情報').trim();
const sections = Array.isArray(ai.sections) ? ai.sections : [];
const watchlistAlerts = Array.isArray(ai.watchlist_alerts) ? ai.watchlist_alerts : [];
const disclaimer = String(ai.disclaimer || '本資訊僅供參考，不構成投資建議，投資請自行評估風險').trim();

const tpe = $now.setZone('Asia/Taipei');
const dateStr = tpe.toFormat('yyyy-MM-dd');
const weekdayMap = ['日', '一', '二', '三', '四', '五', '六'];
const weekday = weekdayMap[tpe.weekday % 7];

const lines = [];
lines.push(`📊 ${dateStr} (週${weekday}) ${headline}`);
lines.push(`資料日期：${tradingDateFmt}（最近交易日盤後）· 新聞：即時頭條`);
lines.push('');
for (const sec of sections) {
  const title = String(sec?.title || '').trim();
  const body = Array.isArray(sec?.lines) ? sec.lines : [];
  if (!title || body.length === 0) continue;
  lines.push(`【${title}】`);
  for (const ln of body) {
    const s = String(ln || '').trim();
    if (s) lines.push(s);
  }
  lines.push('');
}
if (watchlistAlerts.length > 0) {
  lines.push('【自選股提醒】');
  for (const ln of watchlistAlerts) {
    const s = String(ln || '').trim();
    if (s) lines.push(s);
  }
  lines.push('');
}
lines.push('—');
lines.push(`※ ${disclaimer}`);
lines.push('資料來源：TWSE / 鉅亨網');

return [{ json: { text: lines.join('\n') } }];
